// styles.js

import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  outerContainer: {
    flexGrow: 1,
    backgroundColor: 'black',
  },
  imageContainer: {
    flex: 1, // Lägg till flex: 1 för att ta upp tillgängligt utrymme
    position: 'relative',
    marginBottom: theme.spacing(2),
  },
  overlappingImage: {
    position: 'absolute',
    top: '130%',
    left: '15%',
    width: '50%',
    height: 'auto',
  },
  image: {
    marginTop: '5rem',
    marginLeft: '10rem',
    left: '25%',
    width: '75%',
    height: 'auto',
    objectFit: 'cover',
    borderRadius: 0,
  },
  textContainer: {
    flex: 1,
    maxWidth: '50%',
    padding: theme.spacing(2),
    marginTop: '5rem',
    marginLeft: '5rem',
    color: 'white'
  },
}));

export default useStyles;
